}

import { useState } from 'react';
import { BookOpen, RefreshCw, ZoomIn, ZoomOut } from 'lucide-react';

export function SinglePageReader() {
  const [scale, setScale] = useState(1);
  const [page, setPage] = useState(1);
  const totalPages = 4;

  return (
    <div className="w-full max-w-sm mx-auto border border-border bg-neutral-900 text-white rounded-2xl overflow-hidden shadow-2xl p-4">
      {/* Viewer Header Options */}
      <div className="flex items-center justify-between border-b border-white/5 pb-3 mb-4">
        <div className="flex items-center gap-2">
          <BookOpen className="h-5 w-5 text-primary" />
          <span className="text-xs font-semibold">Comimi Slide View</span>
        </div>

        <div className="flex items-center gap-1.5">
          <button 
            onClick={() => setScale((s) => Math.max(0.8, s - 0.1))}
            className="p-1.5 bg-white/5 hover:bg-white/10 rounded-lg text-xs transition-all border border-white/10"
          >
            <ZoomOut className="h-3.5 w-3.5" />
          </button>
          <button 
            onClick={() => setScale((s) => Math.min(1.5, s + 0.1))}
            className="p-1.5 bg-white/5 hover:bg-white/10 rounded-lg text-xs transition-all border border-white/10"
          >
            <ZoomIn className="h-3.5 w-3.5" />
          </button>
        </div>
      </div>

      {/* Comic Page Viewport Panel */}
      <div className="relative aspect-[3/4] bg-neutral-950 rounded-xl overflow-hidden flex items-center justify-center border border-white/5">
        <div 
          style={{ transform: `scale(${scale})` }}
          className="bg-neutral-800/40 border border-white/10 rounded-lg h-5/6 w-5/6 flex items-center justify-center text-center p-6 transition-transform duration-200"
        >
          <div>
            <span className="text-[10px] text-muted-foreground uppercase font-bold tracking-wider">Single Page Panel</span>
            <h3 className="text-4xl font-extrabold text-white mt-2">Page {page}</h3>
            <p className="text-[10px] text-neutral-400 mt-2">Zoom scale: {Math.round(scale * 100)}%</p>
          </div>
        </div>
      </div>

      {/* Navigation Controls footer */}
      <div className="flex items-center justify-between mt-4">
        <button 
          disabled={page <= 1}
          onClick={() => setPage(page - 1)}
          className="px-3 py-1.5 bg-white/5 hover:bg-white/10 disabled:opacity-40 rounded-xl transition-all text-xs font-semibold border border-white/10"
        >
          Prev
        </button>

        <span className="text-xs text-neutral-400 font-mono">Page {page} of {totalPages}</span>

        <button 
          disabled={page >= totalPages}
          onClick={() => setPage(page + 1)}
          className="px-3 py-1.5 bg-white/5 hover:bg-white/10 disabled:opacity-40 rounded-xl transition-all text-xs font-semibold border border-white/10"
        >
          Next
        </button>
      </div>
    </div>
  );
}

